try:
    from pybtex.database import parse_file
except ImportError:
    parse_file = None

try:
    import latexcodec
except ImportError:
    latexcodec = None

FN_BACKLINK_TEXT = util.STX + "3a3c992dd0b930c0f381db89e34ab3a079af69bb" + util.ETX
NBSP_PLACEHOLDER = util.STX + "215bac1bef98f069d37abf25a314daa427390caa" + util.ETX
RE_REF_ID = re.compile(r'(citeref)(\d+)')


def decode_ulatex(value):
    if hasattr(value, 'decode'):
        return value.decode('ulatex')
    return value

class CiteExtension(Extension):
    """ Cite Extension. """

    def __init__(self, *args, **kwargs):
        """ Setup configs. """

        self.config = {
            'PLACE_MARKER':
                ["///Cites Go Here///",
                 "The text string that marks where the cite reference go"],
            'UNIQUE_IDS':
                [False,
                 "Avoid name collisions across "
                 "multiple calls to reset()."],
            "BACKLINK_TEXT":
                ["&#8617;",
                 "The text string that links from the cite "
                 "to the reader's place."],
            "BIBFILE":
                ["","local bibliography file" ],
            "OVERRIDE_BIBFILE":
                ["","local bibliography override file" ],
            "EXT_BIBFILE":
                ["","external bibliography file" ]
        }
        super(CiteExtension, self).__init__(*args, **kwargs)

        # In multiple invocations, emit links that don't get tangled.
        self.unique_prefix = 0
        self.found_refs = {}
        self.used_refs = set()
        self.bib_data={}
        self.override_bib_data={}
        self.ext_bib_data={}
        if parse_file is None:
            sys.stderr.write('Warning: pybtex is not installed; bibliography files will not be loaded.\n')
        if self.getConfig('BIBFILE'):
            sys.stderr.write('Loading %s\n'%self.getConfig('BIBFILE'))
            try:
                if parse_file is not None:
                    self.bib_data = parse_file(self.getConfig('BIBFILE'))
            except Exception as e:
                sys.stderr.write('Error: failure loading bibfile : %s\n'%(e))
        if self.getConfig('OVERRIDE_BIBFILE'):
            sys.stderr.write('Loading %s\n'%self.getConfig('OVERRIDE_BIBFILE'))
            try:
                if parse_file is not None:
                    self.override_bib_data = parse_file(self.getConfig('OVERRIDE_BIBFILE'))
            except Exception as e:
                sys.stderr.write('Error: failure loading bibfile : %s\n'%(e))
        if self.getConfig('EXT_BIBFILE'):
            sys.stderr.write('Loading %s\n'%self.getConfig('EXT_BIBFILE'))
            try:
                if parse_file is not None:
                    self.ext_bib_data = parse_file(self.getConfig('EXT_BIBFILE'))
            except Exception as e:
                sys.stderr.write('Error: failure loading bibfile : %s\n'%(e))

        bib_entries = getattr(self.bib_data, 'entries', {})
        override_entries = getattr(self.override_bib_data, 'entries', {})
        for i in bib_entries:
            if i in override_entries:
                # override local.bib fields only for svn documents
                if decode_ulatex(self.bib_data.entries[i].fields.get('repo','')).endswith('.svn'):
                    for f in self.override_bib_data.entries[i].fields:
                        self.bib_data.entries[i].fields[f] = self.override_bib_data.entries[i].fields[f]

        self.reset()

    def extendMarkdown(self, md, md_globals):
        """ Add pieces to Markdown. """
        md.registerExtension(self)
        self.parser = md.parser
        self.md = md
        # Insert a preprocessor before ReferencePreprocessor
# Don't need Preprocessor
#        md.preprocessors.add(
#            "cite", CitePreprocessor(self), "<reference"
#        )
        # Insert an inline pattern before ImageReferencePattern
        CITE_RE = r'(\{\{cite[\s|]*([^}]*)\}\})'  # blah blah {{cite}} blah
 #       CITE_RE = r'\[\^([^\]]*)\]'  # blah blah [^1] blah
        md.inlinePatterns.add(
            "cite", CitePattern(CITE_RE, self), "<reference"
        )
        # Insert a tree-processor that would actually add the cite div
        # This must be before all other treeprocessors (i.e., inline and
        # codehilite) so they can run on the the contents of the div.
        md.treeprocessors.add(
            "cite", CiteTreeprocessor(self), "_end"
        )

        # Insert a tree-processor that will run after inline is done.
        # In this tree-processor we want to check our duplicate cite tracker
        # And add additional backrefs to the cite pointing back to the
        # duplicated references.
        md.treeprocessors.add(
            "cite-duplicate", CitePostTreeprocessor(self), '>inline'
        )

        # Insert a postprocessor after amp_substitute oricessor
        md.postprocessors.add(
            "cite", CitePostprocessor(self), ">amp_substitute"
        )

    def reset(self):
        """ Clear cite on reset, and prepare for distinct document. """
        #sys.stderr.write('reset \n')
        self.cites = OrderedDict()
        self.unique_prefix += 1
        self.found_refs = {}
        self.used_refs = set()

    def unique_ref(self, reference, found=False):
        """ Get a unique reference if there are duplicates. """
        if not found:
            return reference

        original_ref = reference
        while reference in self.used_refs:
            ref, rest = reference.split(self.get_separator(), 1)
            m = RE_REF_ID.match(ref)
            if m:
                reference = '%s%d%s%s' % (m.group(1), int(m.group(2))+1, self.get_separator(), rest)
            else:
                reference = '%s%d%s%s' % (ref, 2, self.get_separator(), rest)

        self.used_refs.add(reference)
        if original_ref in self.found_refs:
            self.found_refs[original_ref] += 1
        else:
            self.found_refs[original_ref] = 1
        return reference

    def findCitesPlaceholder(self, root):
        """ Return ElementTree Element that contains Cite placeholder. """
        def finder(element):
            for child in element:
                if child.text:
                    if child.text.find(self.getConfig("PLACE_MARKER")) > -1:
                        return child, element, True
                if child.tail:
                    if child.tail.find(self.getConfig("PLACE_MARKER")) > -1:
                        return child, element, False
                child_res = finder(child)
                if child_res is not None:
                    return child_res
            return None

        res = finder(root)
        return res

    def setCite(self, id, text):
        """ Store a cite for later retrieval. """
        self.cites[id] = text

    def get_separator(self):
        if self.md.output_format in ['html5', 'xhtml5']:
            return '-'
        return ':'

    def makeCiteId(self, id):
        """ Return cite link id. """
        if self.getConfig("UNIQUE_IDS"):
            #return 'cite%s%d-%s' % (self.get_separator(), self.unique_prefix, id)
            return 'cite%s%d-%s' % (self.get_separator(), self.unique_prefix, self.cites.index(id)+1)
        else:
            #return 'fn%s%s' % (self.get_separator(), id)
            return 'cite%s%s' % (self.get_separator(), self.cites.index(id)+1)

    def makeCiteRefId(self, id, found=False):
        """ Return cite back-link id. """
        if self.getConfig("UNIQUE_IDS"):
            #return self.unique_ref('citeref%s%d-%s' % (self.get_separator(), self.unique_prefix, id), found)
            return self.unique_ref('citeref%s%d-%s' % (self.get_separator(), self.unique_prefix, self.cites.index(id)+1), found)
        else:
            #return self.unique_ref('citeref%s%s' % (self.get_separator(), id), found)
            return self.unique_ref('citeref%s%s' % (self.get_separator(), self.cites.index(id)+1), found)

    def makeCitesDiv(self, root):
        """ Return div of cites as et Element. """

        if not list(self.cites.keys()):
            return None

        div = util.etree.Element("div")
        div.set('class', 'cite')
        ol = util.etree.SubElement(div, "ol")
        surrogate_parent = util.etree.Element("div")

	# Create bibliography elements
        for id in self.cites.keys():
            li = util.etree.SubElement(ol, "li")
            li.set("id", self.makeCiteId(id))
            backlink = util.etree.Element("a")
            backlink.set("href", "#" + self.makeCiteRefId(id))
            if self.md.output_format not in ['html5', 'xhtml5']:
                backlink.set("rev", "cite")  # Invalid in HTML5
            backlink.set("class", "cite-backref")
            backlink.text = "^"+NBSP_PLACEHOLDER

            # Generate dumb bibliography list element from available data
            # <cite>title, subject, subtitle, doctype[index]</cite>
            cite_template=[]
#            cite_template.append(self.cites[id].get('title',self.cites[id].get('file',id)))
            filelink=None
            for i in ['product','title','subject', 'subtitle','doctype']:
                if i in self.cites[id]:
                    cite_template.append(self.cites[id][i])

            if self.cites[id].get('url'):
                filelink=util.etree.Element("a")
                if self.cites[id].get('file'):
                    filelink.text=', ('+os.path.basename(self.cites[id]['file'])+')'
                else:
                    filelink.text=', ('+self.cites[id].get('url')+')'
                filelink.set("href",self.cites[id].get('url'))
            else:
                if self.cites[id].get('file'):
                        cite_template.append('('+os.path.basename(self.cites[id]['file']+')'))
                else:
                    cite_template.append('('+id+')')

            n = util.etree.SubElement(li, "p")
            backlink.tail=', '.join(cite_template)
            n.append(backlink)
            if filelink is not None:
                n.append(filelink)
        return div

class CitePattern(Pattern):
    """ InlinePattern for cite markers in a document's body text. """

    def __init__(self, pattern, cites):
        super(CitePattern, self).__init__(pattern)
        self.cites = cites

    def handleMatch(self, m):
        #sys.stderr.write('handle match %s \n'%m.group(2))
        #sys.stderr.write('handle match %s \n'%m.group(3))
        # uniq document id
        # Get citation attributes
#        CITE_RE = r'(\{\{cite [^}]*\}\})'  # blah blah {{cite}} blah
        id = None
        cite = {}
        for i in m.group(3).split('|'):
            j = i.split('=', 1)
            if len(j) > 1:
                cite[j[0].strip()] = j[1].strip()

        if cite == {}:
            cite['label'] = m.group(3)

        if 'label' in cite:
            id = cite['label']
            if {} != self.cites.bib_data and id in self.cites.bib_data.entries:
                cite = dict(self.cites.bib_data.entries[id].fields)
                cite = {decode_ulatex(k): decode_ulatex(v) for k, v in cite.items()}
            elif {} != self.cites.override_bib_data and id in self.cites.override_bib_data.entries:
                cite = dict(self.cites.override_bib_data.entries[id].fields)
                cite = {decode_ulatex(k): decode_ulatex(v) for k, v in cite.items()}
            elif {} != self.cites.ext_bib_data and id in self.cites.ext_bib_data.entries:
                cite = dict(self.cites.ext_bib_data.entries[id].fields)
                cite = {decode_ulatex(k): decode_ulatex(v) for k, v in cite.items()}
            else:
                sys.stderr.write("Error: Bibliography reference not found for %s\n" % m.group(2))
        else:
            if 'file' in cite:
                id = cite.get('file')
            else:
                id =m.group(3)
                cite['file']=None
        self.cites.setCite(id, cite)
        #sys.stderr.write("%s\n"%cite)

        if id in self.cites.cites.keys():
            cite_element = util.etree.Element("cite")
            # Generate dumb cite from available data
            # <cite>title, subject, subtitle, doctype[index]</cite>
            title=cite.get('Title',cite.get('title',id))
            cite_template=[]
            if 'product' in cite:
               cite_template.append(cite['product'])
            cite_template.append(title)
            if 'subject' in cite:
               cite_template.append(cite['subject'])
            elif 'subtitle' in cite:
               cite_template.append(cite['subtitle'])
            if 'doctype' in cite:
               cite_template.append(cite['doctype'])

            cite_element.text=', '.join(cite_template)
            sup = util.etree.SubElement(cite_element,"sup")
            a = util.etree.SubElement(sup, "a")
            sup.set('id', self.cites.makeCiteRefId(id, found=True))
            a.set('href', '#' + self.cites.makeCiteId(id))
            if self.cites.md.output_format not in ['html5', 'xhtml5']:
                a.set('rel', 'cite')  # invalid in HTML5
            a.set('class', 'cite-ref')
            if title:
               a.set('title',title)
            a.text = '['+util.text_type(self.cites.cites.index(id) + 1)+']'
            #print  util.etree.tostring(sup, 'utf-8')
            return cite_element
        else:
            return None


class CitePostTreeprocessor(Treeprocessor):
    """ Ammend cite div with duplicates. """

    def __init__(self, cites):
        self.cites = cites

    def add_duplicates(self, li, duplicates):
        """ Adjust current li and add the duplicates: citeref2, citeref3, etc. """
        for link in li.iter('a'):
            # Find the link that needs to be duplicated.
            if link.attrib.get('class', '') == 'cite-backref':
                ref, rest = link.attrib['href'].split(self.cites.get_separator(), 1)
                # Duplicate link the number of times we need to
                # and point the to the appropriate references.
                links = []
                for index in range(2, duplicates + 1):
                    sib_link = copy.deepcopy(link)
                    sib_link.attrib['href'] = '%s%d%s%s' % (ref, index, self.cites.get_separator(), rest)
                    links.append(sib_link)
                    self.offset += 1
                # Add all the new duplicate links.
                el = list(li)[-1]
                for l in links:
                    el.append(l)
                break

    def get_num_duplicates(self, li):
        """ Get the number of duplicate refs of the cite. """
        fn, rest = li.attrib.get('id', '').split(self.cites.get_separator(), 1)
        link_id = '%sref%s%s' % (fn, self.cites.get_separator(), rest)
        return self.cites.found_refs.get(link_id, 0)

    def handle_duplicates(self, parent):
        """ Find duplicate cites and format and add the duplicates. """
        for li in list(parent):
            # Check number of duplicates cites and insert
            # additional links if needed.
            count = self.get_num_duplicates(li)
            if count > 1:
                self.add_duplicates(li, count)

    def run(self, root):
        """ Crawl the cite div and add missing duplicate cites. """
        self.offset = 0
        for div in root.iter('div'):
            if div.attrib.get('class', '') == 'cite':
                # Cites shoul be under the first orderd list under
                # the cite div.  So once we find it, quit.
                for ol in div.iter('ol'):
                    self.handle_duplicates(ol)
                    break


class CiteTreeprocessor(Treeprocessor):
    """ Build and append cite div to end of document. """

    def __init__(self, cites):
        self.cites = cites

    def run(self, root):
        citesDiv = self.cites.makeCitesDiv(root)
        if citesDiv is not None:
            result = self.cites.findCitesPlaceholder(root)
            if result:
                child, parent, isText = result
                ind = parent.getchildren().index(child)
                if isText:
                    parent.remove(child)
                    parent.insert(ind, citesDiv)
                else:
                    parent.insert(ind + 1, citesDiv)
                    child.tail = None
            else:
                root.append(citesDiv)


class CitePostprocessor(Postprocessor):
    """ Replace placeholders with html entities. """
    def __init__(self, cites):
        self.cites = cites

    def run(self, text):
        text = text.replace(
            FN_BACKLINK_TEXT, self.cites.getConfig("BACKLINK_TEXT")
        )
        return text.replace(NBSP_PLACEHOLDER, "&#160;")


def makeExtension(*args, **kwargs):
    """ Return an instance of the CiteExtension """
    return CiteExtension(*args, **kwargs)
